using UnityEditor;
using UnityEngine;

public class BuildAssetBundle : MonoBehaviour
{
    [@MenuItem("Tools/еҚЎзүҢдҝЎжҒҜ")]
    static void OpenCardInfo()
    {
        CardInfoEditor.Open();
    }

    #region bundle

    public static void BuildABs(bool isForce)
    {
        Debug.LogWarning("BuildABs");

        List<AssetBundleBuild> bundles = new List<AssetBundleBuild>();
        var normal = buildConfigs(ConfigManager.Instance.filePath + "/Config", "46afd4738248f13adad6092e7c4f4632076405",
            isForce);
        bundles.AddRange(normal);

        string path = RecordToFile.Instance.GetBundleFilePath();
        RecordToFile.Instance.CreateDirIfNotExists(path, false);
        if (isForce == true)
        {
            BuildPipeline.BuildAssetBundles(path, bundles.ToArray(),
                BuildAssetBundleOptions.DeterministicAssetBundle | BuildAssetBundleOptions.ForceRebuildAssetBundle,
                EditorUserBuildSettings.activeBuildTarget);
        }
        else
        {
            BuildPipeline.BuildAssetBundles(path, bundles.ToArray(), BuildAssetBundleOptions.DeterministicAssetBundle,
                EditorUserBuildSettings.activeBuildTarget);
        }

        RecordToFile.Instance.Clean();
    }

    private static List<AssetBundleBuild> buildConfigs(string sourcePath, string bundleName, bool isForce)
    {
        string[] files = Directory.GetFiles(sourcePath, "*.csv", SearchOption.AllDirectories);
        List<AssetBundleBuild> bundles = new List<AssetBundleBuild>();
        AssetBundleBuild bundle = new AssetBundleBuild();
        bundle.assetBundleName = bundleName;
        List<string> assetNames = new List<string>();
        for (int i = 0; i < files.Length; ++i)
        {
            // иҝҮж»ӨеӨҡиҜӯиЁҖе…ЁиЎЁ
            if (Path.GetFileNameWithoutExtension(files[i]) == "langue")
            {
                continue;
            }
            //"Assets/Game/Config\\achievement.csv"
            assetNames.Add(files[i].Substring(files[i].IndexOf("Assets")));
        }

        bundle.assetNames = assetNames.ToArray();
        bundles.Add(bundle);
        return bundles;
    }

    #endregion


    #region жё…жҘҡ bundle еҗҚз§°

    /// <summary>  
    /// жё…йҷӨд№ӢеүҚи®ҫзҪ®иҝҮзҡ„AssetBundleNameпјҢйҒҝе…Қдә§з”ҹдёҚеҝ…иҰҒзҡ„иө„жәҗд№ҹжү“еҢ…  
    /// </summary>  
    public static void ClearAssetBundlesName()
    {
        int length = AssetDatabase.GetAllAssetBundleNames().Length;
        Debug.Log("ClearAssetBundlesName before:" + length);
        string[] oldAssetBundleNames = new string[length];
        for (int i = 0; i < length; i++)
        {
            oldAssetBundleNames[i] = AssetDatabase.GetAllAssetBundleNames()[i];
        }

        for (int j = 0; j < oldAssetBundleNames.Length; j++)
        {
            Debug.LogWarning(oldAssetBundleNames[j]);
            AssetDatabase.RemoveAssetBundleName(oldAssetBundleNames[j], true);
        }

        length = AssetDatabase.GetAllAssetBundleNames().Length;
        Debug.Log("ClearAssetBundlesName after:" + length);

        var files = Directory.GetFiles(Path.Combine(Application.dataPath, "Game/Config"), "*.csv",
            SearchOption.TopDirectoryOnly);
        for (int i = 0; i < files.Length; ++i)
        {
            var path = files[i].Substring(files[i].IndexOf("Assets"));
            Debug.LogWarning(path);
            AssetImporter assetImporter = AssetImporter.GetAtPath(path);
            assetImporter.SetAssetBundleNameAndVariant("","");
            assetImporter.SaveAndReimport();
        }
    }

    #endregion

    #region и®ҫзҪ®config bundle name

    public static void SetConfigBundleName()
    {
        string sourcePath = ConfigManager.Instance.filePath + "/Config";

        Debug.Log("sourcePath:" + sourcePath);
        Pack(sourcePath, "46afd4738248f13adad6092e7c4f4632076405");
    }

    static void Pack(string source, string name)
    {
        DirectoryInfo folder = new DirectoryInfo(source);
        FileSystemInfo[] files = folder.GetFileSystemInfos();
        int length = files.Length;
        for (int i = 0; i < length; i++)
        {
            if (files[i] is DirectoryInfo)
            {
                Pack(files[i].FullName, name);
            }
            else
            {
                if (!files[i].Name.EndsWith(".meta") && !files[i].Name.EndsWith(".DS_Store"))
                {
                    file(files[i].FullName, name);
                    //Debug.Log("file:" + files[i].FullName);
                }
            }
        }
    }

    static void file(string source, string name)
    {
        string _source = Replace(source);
        string _assetPath = "Assets" + _source.Substring(Application.dataPath.Length);
        string _assetPath2 = _source.Substring(Application.dataPath.Length + 1);
        // Debug.Log("----:" + _source);
        // Debug.Log ("====:" + _assetPath);
        // Debug.Log("++++:" + _assetPath2);

        // иҝҮж»ӨиҜӯиЁҖиЎЁеҺҹиЎЁпјҢдҪҝз”ЁеҲҶиЎЁжӣҝд»Ј
        if (Path.GetFileNameWithoutExtension(source) == "langue")
        {
            return;
        }

        //еңЁд»Јз Ғдёӯз»ҷиө„жәҗи®ҫзҪ®AssetBundleName 
        AssetImporter assetImporter = AssetImporter.GetAtPath(_assetPath);
        if (name != null)
        {
            assetImporter.assetBundleName = name;
        }
        else
        {
            string assetName = _assetPath2.Substring(_assetPath2.IndexOf("/") + 1);
            assetName = assetName.Replace(Path.GetExtension(assetName), ".unity3d");
            Debug.Log(assetName);
            assetImporter.assetBundleName = assetName;
        }
    }

    static string Replace(string s)
    {
        return s.Replace("\\", "/");
    }

    #endregion

    public static void EncyptConfig(bool isEncypt)
    {
        if (isEncypt == false)
        {
            return;
        }

        encyptConfigFile(RecordToFile.Instance.GetBundleFilePath() + "/46afd4738248f13adad6092e7c4f4632076405");
        RecordToFile.Instance.Clean();
    }

    private static void encyptConfigFile(string path)
    {
        Byte[] targetData = RecordToFile.Instance.ReadFromFile(path);
        //еҜ№targetDataдёӯзҡ„жҜҸдёҖbyteйғҪе’Ң10011101еҒҡејӮжҲ–иҝҗз®—гҖӮ  
        targetData = UtilCryptInEditor.EncodeAES(targetData);
        int dataLength = targetData.Length;
        Debug.Log("===============length:" + dataLength);
        if (dataLength > 0)
        {
            string pathFile = path;
            RecordToFile.Instance.SaveByteToFile(targetData, dataLength, pathFile);
        }
    }


    //[@MenuItem("AssetBundles/иҺ·еҸ–дҫқиө–")]
    //static void GetDependencies() {
    //    UnityEngine.Object selectedObject = Selection.activeObject;
    //    if (selectedObject == null) {
    //        return;
    //    }
    //    UnityEngine.Object[] roots = new UnityEngine.Object[] { selectedObject };
    //    Debug.Log("1============================");
    //    var objs = EditorUtility.CollectDependencies(roots);
    //    foreach (var obj in objs) {
    //        Debug.Log(obj.name);
    //        //Debug.Log(obj.GetType().Name);
    //    }

    //    string path = AssetDatabase.GetAssetPath(selectedObject);
    //    var objs2 = AssetDatabase.GetDependencies(path);
    //    Debug.Log("2============================" + path);
    //    foreach (var obj in objs2) {
    //        Debug.Log(obj);
    //    }
    //}
}

