    [MenuItem("Assets/ж¶“еӯҳжӨӮе®ёгғҘеҸҝ/Rename Prefabs", priority = 19)]
    private static void RenamePrefabsContextMenu()
    {
        List<Object> prefabs = new List<Object>();
        foreach (Object obj in Selection.objects)
        {
            if (PrefabUtility.GetPrefabAssetType(obj) != PrefabAssetType.NotAPrefab)
            {
                prefabs.Add(obj);
            }
        }

        List<string> listStr = new List<string>();
        listStr.Add($"йҚҳзҶјо•©йҚ’и·әжӮ•з»ү?йҸӮдјҙо•©йҚ’и·әжӮ•з»ү?);
        foreach (Object prefab in prefabs)
        {
            string path = AssetDatabase.GetAssetPath(prefab);
            string oldName = System.IO.Path.GetFileNameWithoutExtension(path);
            string[] oldNameArr = oldName.Split('_');
            string newName = oldName.Replace($"_{oldNameArr[2]}" , oldNameArr[2]);
            // йҺөСҶо”‘й–Іе¶…жҮЎйҚҡ?
            if (newName != oldName)
            {
                string error = AssetDatabase.RenameAsset(path, newName);
                if (string.IsNullOrEmpty(error))
                {
                    listStr.Add($"{oldName};{newName}");
                    Debug.Log($"й–Іе¶…жҮЎйҚҡе¶ҶеһҡйҚ”? {oldName} йҲ«?{newName}");
                }
                else
                {
                    Debug.LogError($"й–Іе¶…жҮЎйҚҡе¶…гҒ‘з’җ? {error}");
                }
            }
        }
        SaveToExcel(listStr);
        AssetDatabase.Refresh();
    }
    
