        if(buildFolders != null){
            string json = JsonUtility.ToJson(buildFolders);
            string dir = Path.GetDirectoryName(RegistFilePath);
            if(!Directory.Exists(dir)){
                Directory.CreateDirectory(dir);
            }
            File.WriteAllText(RegistFilePath,json);
        }
    }

