    [System.Serializable]
    public class BuildFolders {
        public List<BuildFolder> folders = null;
    }

    [System.Serializable]
    public class BuildFolder {
        public string path;
        // йҸ„оҲҡжғҒзҒҸе——з“ҷйҸӮеӣҰж¬ўйҚҡе қиӢҹйҺҙж„Әз«ҙж¶“зӢқssetBundleй”ӣе®јrue йҺөж’іеҜҳйҸғи·әз“ҷйҸӮеӣҰж¬ўйҗЁеӢ¬еўҰйҚ–е‘ӯжӮ•ж¶“вӮ¬й‘·?
        public bool isMerge;
        // йҸ„оҲҡжғҒй—ҮвӮ¬з‘•дҪёе§һзҖө?
        public bool isEncypt;
    }

    /// ж·ҮжҝҶз“ЁйҗЁеӢ¬жҡҹйҺ№оҶҪжһғжө жғ°зҹҫеҜ°?
    private string RegistFilePath {
        get {
            return Path.Combine(Application.dataPath,".Record/BuildAssets.json");
        }
    }

    private BuildFolders buildFolders = null;

    void OnEnable(){
        buildFolders = getFolders();
    }

    void OnDisable(){
        if(buildFolders != null){
            string json = JsonUtility.ToJson(buildFolders);
            string dir = Path.GetDirectoryName(RegistFilePath);
            if(!Directory.Exists(dir)){
                Directory.CreateDirectory(dir);
            }
            File.WriteAllText(RegistFilePath,json);
        }
    }

    void OnGUI(){
        if(GUILayout.Button("+йҸӮжқҝо–ғйҺөж’іеҜҳйҸӮеӣҰж¬ўжҫ¶?")){
            string temp = EditorUtility.OpenFolderPanel("йҺөж’іеҜҳйҸӮеӣҰж¬ўжҫ¶?,Application.dataPath,"");
            if(!string.IsNullOrEmpty(temp)){
                temp = temp.Substring(temp.IndexOf("Assets"));
                BuildFolder folder = indexOf(temp);
                if(folder == null){
                    folder = new BuildFolder();
                    folder.path = temp;
                    buildFolders.folders.Add(folder);
                }
            }
        }
        if(GUILayout.Button("+еЁЈиҜІе§һиӨ°ж’іеў й–«еӨүи…‘йҸӮеӣҰж¬ўжҫ¶?")){
            Object[] folders = Selection.objects;
            for(int i = 0;i < folders.Length;++i){
                string path = AssetDatabase.GetAssetPath(folders[i]);
                if(Directory.Exists(path)){
                    BuildFolder folder = new BuildFolder();
                    folder.path = path;
                    buildFolders.folders.Add(folder);
                }
            }
        }
        GUILayout.Space(10);

        for(int i = 0;i < buildFolders.folders.Count;++i){
            EditorGUILayout.BeginHorizontal();
            GUILayout.Label(buildFolders.folders[i].path.Replace(Application.dataPath,""),GUILayout.MaxWidth(200));
            buildFolders.folders[i].isMerge = GUILayout.Toggle(buildFolders.folders[i].isMerge,"йҚҡе қиӢҹ");
            buildFolders.folders[i].isEncypt = GUILayout.Toggle(buildFolders.folders[i].isEncypt,"йҚ”зҠІзҳ‘");
            if(GUILayout.Button("Delete")){
                buildFolders.folders.RemoveAt(i);
                break;
            }
            if(GUILayout.Button("SetName")){
                setDirBundleName(buildFolders.folders[i],null);
                EditorUtility.ClearProgressBar();
                AssetDatabase.Refresh();
            }
            if(GUILayout.Button("ClearName")){
                clearBundleName(buildFolders.folders[i]);
                EditorUtility.ClearProgressBar();
                AssetDatabase.Refresh();
            }
            EditorGUILayout.EndHorizontal();
        }
        GUILayout.Space(10);
    
        GUILayout.BeginHorizontal();
        GUI.backgroundColor = Color.red;
        if(GUILayout.Button("еЁ“е‘ҙж«Һ AssetBundleName")){
            if(EditorUtility.DisplayDialog("з’Җп№ҖжҶЎй”ӣ?,"йҸ„оҲҡжғҒеЁ“е‘ҙж«ҺйҺөвӮ¬йҸҲеӨҠеҮЎз’Ғеү§з–ҶйҗЁ?AssetBundleName","йҸ„?,"йҚҡ?)){
                string[] bundles = AssetDatabase.GetAllAssetBundleNames();
                for(int i = 0;i < bundles.Length;++i){
                    EditorUtility.DisplayProgressBar("Clear AssetBundleName",string.Format("[{0}/{1}]{2}",i,bundles.Length,bundles[i]),(float)i/(float)bundles.Length);
                    AssetDatabase.RemoveAssetBundleName(bundles[i],true);
                }
                EditorUtility.ClearProgressBar();
                AssetDatabase.Refresh();
            }
        }
        GUI.backgroundColor = GUI.color;
        if(GUILayout.Button("з’Ғеү§з–Ҷж¶“е©…е ӘйҸӮеӣҰж¬ўжҫ¶еңӯж®‘AssetBundleName")){
            setBundleName();
            AssetDatabase.Refresh();
        }
        GUILayout.EndHorizontal();
        GUILayout.Space(10);

        GUI.backgroundColor = Color.green;
        if(GUILayout.Button("йҺөж’іеҜҳAssetBundle")){
            pickAssetBundles();
            encyptConfig();
            AssetDatabase.Refresh();
        }
    }

    private BuildFolders getFolders(){
        BuildFolders folders = null;
        if(File.Exists(RegistFilePath)){
            string txt = File.ReadAllText(RegistFilePath);
            if(!string.IsNullOrEmpty(txt)){
                folders = JsonUtility.FromJson<BuildFolders>(txt);
            }else{
                Debug.LogError("з’Үеі°еһ№й—„гӮүж®Јй’ҳеҝ”жһғжө ?" + RegistFilePath);
            }
        }else{
            folders = new BuildFolders();
            folders.folders = new List<BuildFolder>();
        }
        return folders;
    }

    private BuildFolder indexOf(string path){
        for(int i = 0;i < buildFolders.folders.Count;++i){
            if(buildFolders.folders[i].path == path){
                return buildFolders.folders[i];
            }
        }
        return null;
    }

    private void setBundleName(){
        Dictionary<string,bool> atlas = new Dictionary<string, bool>();
        for(int i = 0;i < buildFolders.folders.Count;++i){
            atlas.Add(buildFolders.folders[i].path,buildFolders.folders[i].isMerge);
        }
        for(int i = 0;i < buildFolders.folders.Count;++i){
            setDirBundleName(buildFolders.folders[i],atlas);
        }
        EditorUtility.ClearProgressBar();
    }

    private void setDirBundleName(BuildFolder folder,Dictionary<string,bool> atlas){
        string[] files = Directory.GetFiles(folder.path,"*.*",SearchOption.AllDirectories);
        for(int j = 0;j < files.Length;++j){
            if(files[j].EndsWith(".meta")) continue;
            EditorUtility.DisplayProgressBar("Set AssetBundleName:"+folder.path,string.Format("[{0}/{1}]{2}",j,files.Length,files[j]),(float)j/(float)files.Length);
            bool isMerge = folder.isMerge;
            if(atlas != null){
                string dir = Path.GetDirectoryName(files[j]);
                // йҸ„оҲҡжғҒйҸҲеӨҠеҸҫжө ж Ёжҙҝз’ҮпёҫзІҸйҗЁеӢ«еҮЎз’Ғеү§з–ҶйҸӮеӣҰж¬ўжҫ¶?
                bool hasOtherMatch = false;
                while(!string.IsNullOrEmpty(dir)){
                    if(atlas.ContainsKey(dir)){
                        isMerge = atlas[dir];
                        if(dir.Length > folder.path.Length){
                            hasOtherMatch = true;
                        }
                        break;
                    }
                    dir = Path.GetDirectoryName(dir);
                }
                if(hasOtherMatch) continue;
            }
            AssetImporter importer = AssetImporter.GetAtPath(files[j]);
            string fileDir = Path.GetDirectoryName(files[j]);
            string bundleName = isMerge ? fileDir.Substring(fileDir.LastIndexOf('/')+1) : Path.GetFileName(files[j]);
            importer.assetBundleName = string.Format("{0}/{1}",fileDir,bundleName);
        }
    }

    private void clearBundleName(BuildFolder folder){
        string[] files = Directory.GetFiles(folder.path,"*.prefab",SearchOption.AllDirectories);
        for(int i = 0;i < files.Length;++i){
            EditorUtility.DisplayProgressBar("Clear AssetBundleName:"+folder.path,string.Format("[{0}/{1}]{2}",i,files.Length,files[i]),(float)i/(float)files.Length);
            AssetImporter asset = AssetImporter.GetAtPath(files[i]);
            asset.assetBundleName = string.Empty;
        }
    }

    /// йҺөж’іеҜҳ
    private void pickAssetBundles(){
        // йҚ’ж¶ҳзј“ж¶“еӯҳжӨӮйҸӮеӣҰж¬ўжҫ¶?
        string output = Path.Combine(Application.streamingAssetsPath,getPlatform());
        if(!Directory.Exists(output)){
            Directory.CreateDirectory(output);
        }
        BuildPipeline.BuildAssetBundles(output,BuildAssetBundleOptions.ChunkBasedCompression,EditorUserBuildSettings.activeBuildTarget);
        Debug.Log("AssetBundle йҺөж’іеҜҳзҖ№еұҫзҳҜ");
    }

    /// йҚ”зҠІзҳ‘й–°е¶Үз–ҶйҸӮеӣҰж¬ў
    private void encyptConfig(){
        for(int i = 0;i < buildFolders.folders.Count;++i){
            if(buildFolders.folders[i].isEncypt){
                string dir = buildFolders.folders[i].path.ToLower();
                string path = string.Format("{0}/{1}/{2}{3}",Application.streamingAssetsPath,getPlatform(),dir,dir.Substring(dir.LastIndexOf('/')));
                if(File.Exists(path)){
                    byte[] bytes = File.ReadAllBytes(path);
                    bytes = EncyptByte(bytes);
                    File.WriteAllBytes(path,bytes);
                    Debug.Log("йҚ”зҠІзҳ‘й–°е¶Үз–ҶйҸӮеӣҰж¬ўзҖ№еұҫеһҡй”ӣ?+path);
                }
            }
        }
    }

    /// йҚ”зҠІзҳ‘ жҫ¶е¶…еҹ— RecordToFile.EncyptByte
    private System.Byte[] EncyptByte(System.Byte[] b) {
        for (int i = 0; i < b.Length; i ++) {
            b[i] = (System.Byte)(b[i] ^ 157);
        }
        return b;
    }

    private string getPlatform(){
#if UNITY_ANDROID
		return "android";
#elif UNITY_IOS
		return "iphone";
#elif UNITY_STANDALONE
		return "pc";
#endif
    }
}

