using TMPro;
using UnityEditor.VersionControl;
using Debug = UnityEngine.Debug;
using Object = UnityEngine.Object;

public class CustomTool
{
    #region йҚҷжЁ»жҙҝзҖөз…ҺеҸҶйҗЁеҲҫngйҗЁеӢ¬зүёеҜ®?

    /// йҸҚз…ҺзҙЎйҚ–жңҘIйҚҳзҶ·оқҗзҒҸеҝ“жөҳйҗЁеӢ¬зүёеҜ®?
    [MenuItem("Tools/Png/йҸҚз…ҺзҙЎйҚ–жңҘIзҒҸеҝ“жөҳ")]
    public static void formatUIOrigin()
    {
        Object[] textures = Selection.GetFiltered(typeof(Texture2D), SelectionMode.DeepAssets);
        Selection.objects = new Object[0];
        foreach (Texture2D texture in textures)
        {
            string path = AssetDatabase.GetAssetPath(texture);
            Debug.Log(path);
            formatUI(path);
        }

        AssetDatabase.Refresh();
    }

    public static void formatUI(string path)
    {
        TextureImporter ti = AssetImporter.GetAtPath(path) as TextureImporter;
        ti.textureType = TextureImporterType.Sprite;
        ti.spriteImportMode = SpriteImportMode.Single;
        ti.sRGBTexture = true;
        ti.alphaSource = TextureImporterAlphaSource.FromInput;
        ti.npotScale = TextureImporterNPOTScale.None;
        ti.alphaIsTransparency = true;
        ti.mipmapEnabled = false;
        ti.wrapMode = TextureWrapMode.Clamp;
        ti.filterMode = FilterMode.Bilinear;
        if (ti.maxTextureSize > 2048)
        {
            ti.maxTextureSize = 2048;
        }

        // йҺөе¬«жәҖйҗ—е ўзӨҢйҸүж„ӯзүёеҜ®еҝ“еҜІйҸғи·әжӮ“е§қгғҘеёҮзјӮ?
        if (!path.Contains("Game_PC"))
        {
            // compress
            TextureImporterPlatformSettings ts = new TextureImporterPlatformSettings();
            ts.name = "DefaultTexturePlatform";
            ts.format = TextureImporterFormat.Automatic;
            ts.textureCompression = TextureImporterCompression.CompressedHQ;
            ts.compressionQuality = 100;
            ts.crunchedCompression = true;
            ti.SetPlatformTextureSettings(ts);
            
            ts.name = "Android";
            ts.overridden = true;
            ts.format = TextureImporterFormat.ASTC_6x6;
            ts.compressionQuality = 100;
            ti.SetPlatformTextureSettings(ts);

            ts.name = "iPhone";
            ts.overridden = true;
            ts.format = TextureImporterFormat.ASTC_6x6;
            ts.compressionQuality = 100;
            ti.SetPlatformTextureSettings(ts);
        }

        AssetDatabase.ImportAsset(path);
    }

    /// <summary>
    /// йҚҘеү§еў–йҚҳе¬¬зјүжҰӣжЁҝо…»з’Ғеү§з–Ҷ
    /// </summary>
    // [MenuItem("Tools/Png/йҚҳе¬¬зјүйҚҘеү§еў–(Default)")]
    public static void CompressedByAndroid()
    {
        Object[] textures = Selection.GetFiltered(typeof(Texture2D), SelectionMode.DeepAssets);
        Selection.objects = new Object[0];
        foreach (Texture2D texture in textures)
        {
            string path = AssetDatabase.GetAssetPath(texture);
            TextureImporter ti = AssetImporter.GetAtPath(path) as TextureImporter;
            var android = new TextureImporterPlatformSettings();
            android.overridden = true;
            android.name = "Android";
            if (ti.DoesSourceTextureHaveAlpha())
            {
                android.format = TextureImporterFormat.ETC2_RGBA8;
            }
            else
            {
                android.format = TextureImporterFormat.ETC2_RGB4;
            }

            android.crunchedCompression = true;
            android.compressionQuality = 100;
            ti.SetPlatformTextureSettings(android);

            // var iOS = new TextureImporterPlatformSettings();
            // iOS.overridden = true;
            // iOS.name = "iOS";
            // if (ti.DoesSourceTextureHaveAlpha())
            // {
            //     iOS.format = TextureImporterFormat.ASTC_RGBA_6x6;
            // }
            // else
            // {
            //     iOS.format = TextureImporterFormat.ASTC_RGB_6x6;
            // }
            //
            // iOS.crunchedCompression = true;
            // iOS.compressionQuality = 100;
            // ti.SetPlatformTextureSettings(iOS);

            // AssetDatabase.ImportAsset(path);
        }

        AssetDatabase.Refresh();
    }

    /// ж¶“е¶…еёҮзјӮ?iOS йҗЁеүҮk2d з’җжқ‘жөҳз’җг„©еҷә
    [MenuItem("Tools/Png/ж¶“е¶…еёҮзјӮп№ҠOSз»”з–¶K2Dз’җжқ‘жөҳ")]
    public static void unCompressedIOSTk2DTex()
    {
        Object[] textures = Selection.GetFiltered(typeof(Texture2D), SelectionMode.DeepAssets);
        Selection.objects = new Object[0];
        foreach (Texture2D texture in textures)
        {
            string path = AssetDatabase.GetAssetPath(texture);
            TextureImporter ti = AssetImporter.GetAtPath(path) as TextureImporter;
            // base
            ti.textureType = TextureImporterType.Sprite;
            ti.spriteImportMode = SpriteImportMode.Single;
            ti.sRGBTexture = true;
            ti.alphaSource = TextureImporterAlphaSource.FromInput;
            ti.npotScale = TextureImporterNPOTScale.None;
            ti.alphaIsTransparency = true;
            ti.mipmapEnabled = false;
            ti.wrapMode = TextureWrapMode.Clamp;
            ti.filterMode = FilterMode.Bilinear;
            if (ti.maxTextureSize > 2048)
            {
                ti.maxTextureSize = 2048;
            }

            // override
            TextureImporterPlatformSettings setting = ti.GetPlatformTextureSettings("iPhone");
            setting.overridden = true;
            if (setting.maxTextureSize > 2048)
            {
                setting.maxTextureSize = 2048;
            }

            setting.format = TextureImporterFormat.RGBA32;
            ti.SetPlatformTextureSettings(setting);
            AssetDatabase.ImportAsset(path);
        }

        AssetDatabase.Refresh();
    }

    [MenuItem("Tools/Png/йҚҘеү§еў–йҗЁеҮұacking Tagз’Ғеү§з–Ҷж¶“зҜңngйҸӮеӣҰж¬ўйҚҡ?)]
    public static void SetPngPackingTag2PngName()
    {
        Object[] textures = Selection.GetFiltered(typeof(Texture2D), SelectionMode.DeepAssets);
        for (int i = 0; i < textures.Length; ++i)
        {
            string path = AssetDatabase.GetAssetPath(textures[i]);
            TextureImporter importer = AssetImporter.GetAtPath(path) as TextureImporter;
            if (importer != null)
            {
                importer.spritePackingTag = textures[i].name;
            }

            AssetDatabase.ImportAsset(path);
        }

        AssetDatabase.Refresh();
        // string path = AssetDatabase.GetAssetPath(Selection.activeObject);
        // if(Directory.Exists(path)){
        // 	string[] files = Directory.GetFiles(path,"*.png");
        // 	for(int i = 0;i < files.Length;++i){
        // 		TextureImporter tex = AssetImporter.GetAtPath(files[i]) as TextureImporter;
        // 		if(tex != null){
        // 			tex.spritePackingTag = tex.name;
        // 		}
        // 		Debug.LogWarning(files[i]);
        // 		AssetDatabase.ImportAsset(files[i]);
        // 		if(i == 0) break;
        // 	}
        // 	AssetDatabase.Refresh();
        // }
    }

    #endregion

    // [MenuItem("Assets/HashPath")]
    // public static void CalcuatePrefabHash()
    // {
    //     DirectoryInfo AssetDir = new DirectoryInfo(Application.dataPath);
    //     string path = AssetDatabase.GetAssetPath(Selection.activeObject);
    //     path = path
    //         .Replace(AssetDir.FullName, "")
    //         .Replace('\\', '.')
    //         .Replace('/', '.')
    //         .Replace(" ", "_")
    //         .ToLower();
    //     string hash = Tangzx.ABSystem.HashUtil.Get(path);
    //     Debug.LogFormat("{0} == {1}", path, hash);
    // }

    [MenuItem("Tools/й–«еӮһеҺӨ/йҸҮеӯҳжҹҠйҚҰзғҳж«ҷ")]
    public static void AdjustResetScene()
    {
        AdjustManager.Instance.BuildCommand();
