using System.IO;
using System;
using UnityEditor;
using UnityEngine;

namespace YYZY.BuildPipeline
{
    [InitializeOnLoad]
    public class BuildPipeline
    {
        /// <summary>дёҺ Build Pipeline зӘ—еҸЈдёӯжөҒж°ҙзәҝеҗҚз§°дёҖиҮҙпјӣ<see cref="RunHotUpdatePipeline"/> дјҡи·‘иҜҘзәҝ<strong>е…ЁйғЁ</strong>жңүж•ҲжӯҘйӘӨгҖӮ</summary>
        public const string HotUpdatePipelineName = "зғӯжӣҙ";

        private const string BatchExitAfterDonePrefKey = "BuildPipeline.BatchExitAfterDone";

        private enum ExecuteState
        {
            NotStart = -1,
            Executing,
            Suspend,
            Succeeded,
            Canceled,
        }

        public static string ConfigFilePath
        {
            get
            {
                var temp = EditorPrefs.GetString(ConfigPath);
                if (!File.Exists(temp))
                {
                    ConfigFilePath = Path.Combine(Application.dataPath, DefaultConfigFilePath);
                }

                return temp;
            }
            set => EditorPrefs.SetString(ConfigPath, value);
        }
        private const string DefaultConfigFilePath = "EditorConfig/BuildPipelineConfig.bytes";
        private static string ExecuteVariable => Path.Combine(Application.dataPath, "BuildPipeline.Variable");
        private static string ConfigPath => Path.Combine(Application.dataPath, "BuildPipeline.ConfigPath");

        private static Serializer serializer = new Serializer();
        private static BuildPipelineConfig config = null;
        private static ExecuteState executeState = ExecuteState.NotStart;

        static BuildPipeline()
        {
            Debug.Log($"===============Initialize BuildPipeline: {(ExecuteState)EditorPrefs.GetInt(ExecuteVariable)}===============");
            if ((ExecuteState)EditorPrefs.GetInt(ExecuteVariable) == ExecuteState.Suspend)
            {
                Debug.Log("=====Resume the build step=====");
                ExecuteContinued();
            }

            if (Array.IndexOf(Environment.GetCommandLineArgs(), "-batchmode") < 0)
                EditorPrefs.SetBool(BatchExitAfterDonePrefKey, false);
        }

        public static BuildPipelineConfig Config
        {
            get
            {
                if (config == null)
                {
                    config = new BuildPipelineConfig();
                    var path = ConfigFilePath;
                    if (File.Exists(path))
                    {
                        var bytes = File.ReadAllBytes(path);
                        using (var r = serializer.CreateReader(new MemoryStream(bytes)))
                        {
                            r.Version = r.ReadInt32();
                            config.Deserialize(r);
                        }
                    }
                }

                return config;
            }
        }

        public static bool IsBuilding { private set; get; }

        public static void Execute(string pipeline)
        {
            var pipe = Config.GetPipeLine(pipeline);
            if (pipe != null)
            {
                Config.ExecuteStack.Clear();
                ExecutePipeline(pipe, false);
            }
            else
            {
                Debug.Log("pipeline " + pipeline + " not found!");
            }
        }

        /// <summary>
        /// ж— еҸӮе…ҘеҸЈпјҢдҫӣ batпјҡ<c>-executeMethod YYZY.BuildPipeline.BuildPipeline.RunHotUpdatePipeline</c>гҖӮ
        /// жү§иЎҢеҗҚдёә <see cref="HotUpdatePipelineName"/> зҡ„жөҒж°ҙзәҝдёӯзҡ„<strong>е…ЁйғЁжңүж•ҲжӯҘйӘӨ</strong>пјҲдёҺзј–иҫ‘еҷЁйҮҢж•ҙжқЎзәҝжү§иЎҢдёҖиҮҙпјҢйқһд»…еӢҫйҖүжӯҘйӘӨпјүгҖӮ
        /// </summary>
        public static void RunHotUpdatePipeline()
        {
            if (!IsCommandLineBatchMode())
            {
                Execute(HotUpdatePipelineName);
                return;
            }

            Debug.Log($"BuildPipeline.RunHotUpdatePipeline (batch, all steps): '{HotUpdatePipelineName}'");
            BeginBatchCli(HotUpdatePipelineName, selectedOnly: false);
        }

        private static bool IsCommandLineBatchMode()
        {
            return Array.IndexOf(Environment.GetCommandLineArgs(), "-batchmode") >= 0;
        }

        private static void BeginBatchCli(string pipeline, bool selectedOnly)
        {
            if (string.IsNullOrEmpty(pipeline))
            {
                Debug.LogError("BuildPipeline CLI: pipeline name is empty.");
                EditorApplication.Exit(1);
                return;
            }

            EditorPrefs.SetBool(BatchExitAfterDonePrefKey, true);
            var mode = selectedOnly ? "Selected" : "Full";
            Debug.Log($"BuildPipeline CLI (batch) mode={mode} pipeline='{pipeline}'");

            var pipe = Config.GetPipeLine(pipeline);
            if (pipe == null)
            {
                Debug.LogError("pipeline " + pipeline + " not found!");
                ClearBatchExitRequest();
                EditorApplication.Exit(1);
                return;
            }

            try
            {
                Config.ExecuteStack.Clear();
                ExecutePipeline(pipe, selectedOnly);
            }
            catch (Exception e)
            {
                Debug.LogException(e);
                ClearBatchExitRequest();
                EditorApplication.Exit(1);
                return;
            }

            TryBatchExitNowIfDone();
        }

        private static void ClearBatchExitRequest()
        {
            EditorPrefs.SetBool(BatchExitAfterDonePrefKey, false);
        }

        private static void TryBatchExitNowIfDone()
        {
            if (!EditorPrefs.GetBool(BatchExitAfterDonePrefKey, false))
                return;
            if (!IsDone())
                return;

            ClearBatchExitRequest();
            var code = LastRunSucceeded ? 0 : 1;
            if (code != 0)
                Debug.LogError("Build pipeline finished with errors or was canceled.");
            EditorApplication.Exit(code);
        }

        public static void ExecuteSelected(string pipeline)
        {
            var pipe = Config.GetPipeLine(pipeline);
            if (pipe != null)
            {
                Config.ExecuteStack.Clear();
                ExecutePipeline(pipe, true);
            }
            else
            {
                Debug.Log("pipeline " + pipeline + " not found!");
            }
        }

        public static void SaveConfig()
        {
            if (config != null)
            {
                var path = ConfigFilePath;
                using (var w = serializer.CreateWriter(File.OpenWrite(path)))
                {
                    w.Version = BuildPipelineConfig.APIConfigVersion;
                    w.Write(BuildPipelineConfig.APIConfigVersion);
                    w.Write(config);
                }
                AssetDatabase.Refresh();
            }
        }

        public static void ClearConfig()
        {
            config = null;
        }

        internal static void ExecuteContinued()
        {
            SetExecuteState(ExecuteState.Executing);
            while (!Config.IsExecuteFinished)
            {
                if (EditorApplication.isCompiling)
                {
                    SaveConfig();
                    SetExecuteState(ExecuteState.Suspend);
                    Debug.Log("-----Jump out the build step-----");
                    return;
                }

                var lastIndex = Config.ExecuteStack.Count - 1;
                var step = Config.ExecuteStack[lastIndex];
                Config.ExecuteStack.RemoveAt(lastIndex);
                if (step != null)
                {
                    using (new LogStamp("Excute Pipline:" + step.Name))
                    {
                        if (!ExecuteStep(step))
                        {
                            SetExecuteState(ExecuteState.Canceled);
                            TryBatchExitNowIfDone();
                            return;
                        }
                    }
                }
            }
            SetExecuteState(ExecuteState.Succeeded);
            TryBatchExitNowIfDone();
        }

        internal static bool ExecuteStep(BuildPipelineStep step)
        {
            try
            {
                IsBuilding = true;
                if (step.IsBuildActionValid)
                {
                    step.BuildAction?.Invoke();
                }
            }
            catch (Exception e)
            {
                throw;
            }
            finally
            {
                IsBuilding = false;
            }

            return true;
        }

        internal static void ExecuteSelected(BuildPipelineLine line)
        {
            Config.ExecuteStack.Clear();
            ExecutePipeline(line, true);
        }

        internal static void Execute(BuildPipelineLine line)
        {
            Config.ExecuteStack.Clear();
            ExecutePipeline(line, false);
        }

        internal static bool IsDone()
        {
            return executeState == ExecuteState.Succeeded || executeState == ExecuteState.Canceled;
        }

        internal static bool LastRunSucceeded => executeState == ExecuteState.Succeeded;

        private static void ExecutePipeline(BuildPipelineLine line, bool selectedOnly)
        {
            if (line != null)
            {
                if (Config.ExecuteStack.Count > 0)
                {
                    Config.ExecuteStack.RemoveAt(Config.ExecuteStack.Count - 1);
                }

                //еөҢеҘ—жү§иЎҢ
                for (int i = line.Steps.Count - 1; i >= 0; --i)
                {
                    var step = line.Steps[i];
                    if (step.IsBuildActionValid && (!selectedOnly || step.Selected))
                    {
                        Config.ExecuteStack.Add(step);
                    }
                }
                ExecuteContinued();
            }
        }

        private static void SetExecuteState(ExecuteState executeState)
        {
            BuildPipeline.executeState = executeState;
            EditorPrefs.SetInt(ExecuteVariable, (int)executeState);
        }
    }
}

